for example 
`int main() {

    LFortranJSON level3(kObjectType);
    level3.AddMember("key3", "value3");

    LFortranJSON level2(kObjectType);
    level2.AddMember("key2", level3);

    LFortranJSON level1(kObjectType);
    level1.AddMember("key1", level2);

    LFortranJSON root(kObjectType);
    root.AddMember("root", level1);

    std::cout << root.GetValue() << std::endl;

    return 0;
